import { defineComponent, computed, h, type PropType } from 'vue';
import { getButtonStyleKeys, isButtonDisabled } from '../lib/core';
import type { ButtonVariant, ButtonSize } from '../lib/core';
import styles from './button.module.scss';

export const TButton = defineComponent({
  name: 'TButton',
  props: {
    variant: {
      type: String as PropType<ButtonVariant>,
      default: 'default',
    },
    size: {
      type: String as PropType<ButtonSize>,
      default: 'default',
    },
    loading: { type: Boolean, default: false },
    disabled: { type: Boolean, default: false },
    type: {
      type: String as PropType<'button' | 'submit' | 'reset'>,
      default: 'button',
    },
  },
  setup(props, { slots }) {
    const styleKeys = computed(() => getButtonStyleKeys(props.variant, props.size));
    const computedDisabled = computed(() => isButtonDisabled(props.disabled, props.loading));
    const classes = computed(() => [
      styles[styleKeys.value.base],
      styles[styleKeys.value.variant],
      styles[styleKeys.value.size],
    ]);

    return () => {
      const children: any[] = [];
      if (props.loading) {
        children.push(
          h('svg', {
            class: styles.spinner,
            xmlns: 'http://www.w3.org/2000/svg',
            width: '16',
            height: '16',
            viewBox: '0 0 24 24',
            fill: 'none',
            stroke: 'currentColor',
            'stroke-width': '2',
            'stroke-linecap': 'round',
            'stroke-linejoin': 'round',
          }, [h('circle', { cx: '12', cy: '12', r: '10' })])
        );
      }
      if (slots.default) {
        children.push(slots.default());
      }
      return h('button', {
        class: classes.value,
        disabled: computedDisabled.value,
        type: props.type,
      }, children);
    };
  },
});

export default TButton;

@use 'sass:color';
@use 'variables/colors' as *;

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: $spacing-2;
  white-space: nowrap;
  border-radius: $radius;
  font-size: $text-sm;
  font-weight: $font-medium;
  transition: all $transition-fast;
  cursor: pointer;
  outline: none;

  &:focus-visible {
    outline: none;
    box-shadow: 0 0 0 2px $background, 0 0 0 4px $ring;
  }

  &:disabled,
  &.disabled {
    pointer-events: none;
    opacity: 0.5;
    cursor: not-allowed;
  }

  svg {
    pointer-events: none;
    width: 1em;
    height: 1em;
  }

  // 尺寸变体
  &.sizeDefault {
    height: 2.25rem;
    padding: 0 $spacing-4;

    &.hasIcon {
      padding-inline: $spacing-3;
    }
  }

  &.sizeSm {
    height: 2rem;
    border-radius: $radius-sm;
    padding: 0 $spacing-3;
    font-size: $text-xs;

    &.hasIcon {
      padding-inline: $spacing-2;
      gap: $spacing-1;
    }
  }

  &.sizeLg {
    height: 2.5rem;
    border-radius: $radius-md;
    padding: 0 $spacing-6;
    font-size: $text-base;

    &.hasIcon {
      padding-inline: $spacing-4;
    }
  }

  &.sizeIcon {
    height: 2.25rem;
    width: 2.25rem;
    padding: 0;
  }

  // 样式变体
  &.variantDefault {
    background-color: $primary;
    color: $primary-foreground;
    border: none;
    box-shadow: $shadow-sm;

    &:hover:not(:disabled) {
      background-color: color.mix(black, $primary, 10%);
    }

    &:active:not(:disabled) {
      background-color: color.mix(black, $primary, 20%);
    }
  }

  &.variantDestructive {
    background-color: $destructive;
    color: $destructive-foreground;
    border: none;
    box-shadow: $shadow-sm;

    &:hover:not(:disabled) {
      background-color: color.mix(black, $destructive, 10%);
    }
  }

  &.variantOutline {
    background-color: transparent;
    color: $foreground;
    border: 1px solid $border;
    box-shadow: $shadow-sm;

    &:hover:not(:disabled) {
      background-color: $accent;
      color: $accent-foreground;
    }
  }

  &.variantSecondary {
    background-color: $secondary;
    color: $secondary-foreground;
    border: none;
    box-shadow: $shadow-sm;

    &:hover:not(:disabled) {
      background-color: color.mix(black, $secondary, 10%);
    }
  }

  &.variantGhost {
    background-color: transparent;
    color: $foreground;

    &:hover:not(:disabled) {
      background-color: $accent;
      color: $accent-foreground;
    }
  }

  &.variantLink {
    background-color: transparent;
    color: $primary;
    text-decoration: underline;
    text-underline-offset: 4px;

    &:hover:not(:disabled) {
      text-decoration: none;
    }
  }
}
